inline bool is_self(const std::string& str)
{
	if (str.length() == 4) {
		char c1 = str[0];
		if (c1 == 's' || c1 == 'S') {
			char c2 = str[1];
			if (c2 == 'e' || c1 == 'E') {
				char c3 = str[2];
				if (c3 == 'l' || c1 == 'L') {
					char c4 = str[3];
					if (c4 == 'f' || c1 == 'F') {
						return true;
					}
				}
			}
		}
	}
	
	return false;
}

