inline bool hasXMLCharsToMangle(const std::string& input)
{
	return input.find_first_of("&\"<>", 0, 4) != std::string::npos;
}

inline std::string escapeXMLEntities(const std::string& input)
{
	std::string result;
	result.reserve(input.length() + 4);
	std::string::const_iterator ci = input.begin();
	std::string::const_iterator cend = input.end();
	while (ci != cend) {
		char c = *ci++;
		switch (c) {
		case '&':
			result += "&amp;";
			break;
		case '\"':
			result += "&quot;";
			break;
		case '<':
			result += "&lt;";
			break;
		case '>':
			result += "&gt;";
			break;
		default:
			result += c;
			break;
		}
	}
	return result;
}

inline bool hasJSONCharsToMangle(const std::string& input)
{
	return input.find_first_of("\"'\\\b\f\n\r\t", 0, 8) != std::string::npos;
}

inline std::string escapeJSONChars(const std::string& input)
{
	std::string result;
	result.reserve(input.length() + 4);
	std::string::const_iterator ci = input.begin();
	std::string::const_iterator cend = input.end();
	while (ci != cend) {
		char c = *ci++;
		switch (c) {
		case '\"':
			result += "\\\"";
			break;
		case '\'':
			result += "\\'";
			break;
		case '\\':
			result += "\\\\";
			break;
		case '\b':
			result += "\\b";
			break;
		case '\f':
			result += "\\f";
			break;
		case '\n':
			result += "\\n";
			break;
		case '\r':
			result += "\\r";
			break;
		case '\t':
			result += "\\t";
			break;
		default:
			result += c;
			break;
		}
	}
	return result;
}





