class QDException : public EmdrosException {
public:
	QDException(const std::string& msg) : EmdrosException(msg) {};
	~QDException() {};
};


typedef std::map<std::string, std::string> AttributeMap;


extern std::string getAttribute(const AttributeMap& attrs, const std::string& key) throw(QDException);



class QDDocHandler {
 public:
	QDDocHandler() {};
	virtual ~QDDocHandler() {};
	virtual void startElement(const std::string& tag, const AttributeMap& attrs) throw(QDException) {};
	virtual void endElement(const std::string& tag) throw(QDException) {};
	virtual void startDocument(void) throw(QDException) {};
	virtual void endDocument(void) throw(QDException) {};
	virtual void text(const std::string& str) throw(QDException) {};
	virtual void comment(const std::string& str) throw(QDException) {};
};



class QDParser {
 protected:
	const static std::string NOTAG;
	eCharsets m_encoding;
	int m_line;
	int m_column;
	int m_tag_depth;
	AttributeMap m_attributes;
	std::istream *m_pInStream;
	QDDocHandler *m_pDH;
	std::string m_tag_name;
	std::string m_lvalue;
	std::string m_rvalue;
	bool m_end_of_line;
	char m_quote_char;
	std::string m_entity;
	std::string m_text;
	

	typedef enum {
		TEXT,
		ENTITY,
		OPEN_TAG,
		CLOSE_TAG,
		START_TAG,
		ATTRIBUTE_LVALUE,
		ATTRIBUTE_EQUAL,
		ATTRIBUTE_RVALUE,
		QUOTE,
		IN_TAG,
		SINGLE_TAG,
		COMMENT,
		DONE,
		DOCTYPE,
		IN_XMLDECLARATION,
		BEFORE_XMLDECLARATION,
		OPEN_XMLDECLARATION,
		CDATA
	} eQDStates;


	typedef std::stack<eQDStates> StateStack;
	StateStack m_stack;
 public:
	QDParser();
	~QDParser();
	void parse(QDDocHandler *pDH, std::istream *pStream) throw(QDException);

 protected:
	void cleanUp() 
	{
		if (bot) {
			delete[] bot;
			bot = 0;
		}
	}
	void eraseAttributes()
	{
		m_attributes.clear();
	}

	bool myisspace(char nc)
	{
		return nc == (int) ' ' 
			|| nc == (int) '\n' 
			// || nc == (int) '\r'  // '\r' is converted to '\n' by getNextChar().
			|| nc == (int) '\t' 
			|| nc == (int) '\x0b' // Vertical space
			|| nc == (int) '\f';
	}

	void pushState(eQDStates state) {
		m_stack.push(state);
	}
		

	eQDStates popState(void) throw(QDException)
	{
		if (!m_stack.empty()) {
			eQDStates result = m_stack.top();
			m_stack.pop();
			return result;
		} else {
			except("QDParser::popState: Attempted to pop off of an empty StateStack.");
			return TEXT; // Just to fool the compiler into giving now warning!
		}
	}

	void handle_entity(eQDStates mode) throw(QDException);

	std::string state2string(eQDStates e);

	void except(const std::string& s) throw(QDException);

	char getNextChar(void) throw(QDException);

	void fillBuffer(void);
 protected:
	bool hasMoreInput() { return eof == 0 || cur != eof; };

 private:
	char *bot, *tok, *ptr, *cur, *pos, *lim, *top, *eof;
};



